create table public.integration_exports (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  cycle_id uuid not null references public.assessment_cycles(id) on delete cascade,  export_type text not null,  target_system text not null,  schema_version text not null default 'v1',  status text not null default 'pending' check (status in ('pending','processed','failed')),  payload_json jsonb,  payload_signature text,  generated_at timestamptz not null default now(),  processed_at timestamptz);create table public.audit_log (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  actor_user_id uuid references public.users(id),  entity text not null,  entity_id uuid,  action text not null,  payload_json jsonb,  created_at timestamptz not null default now());create index on public.audit_log (tenant_id, entity, created_at desc);